//! Differential test: assert our encoder matches the Python `sentencepiece`
//! oracle token-for-token.
//!
//! The oracle file `oracle/cases.tsv` is generated by `oracle/gen_oracle.py`
//! (see README.md). Until it has been generated the test is skipped with a
//! message rather than failing, so `cargo test` is green on a fresh checkout.

use std::path::Path;

use sentencepiece_rs::SentencePieceProcessor;

const MODEL: &str = "tests/models/botchan_1000_bpe.model";
const CASES: &str = "oracle/cases.tsv";

fn hex_decode(s: &str) -> Vec<u8> {
    let b = s.as_bytes();
    (0..b.len() / 2)
        .map(|i| {
            let hi = (b[2 * i] as char).to_digit(16).unwrap();
            let lo = (b[2 * i + 1] as char).to_digit(16).unwrap();
            (hi * 16 + lo) as u8
        })
        .collect()
}

#[test]
fn bpe_matches_python_oracle() {
    if !Path::new(CASES).exists() {
        eprintln!(
            "skipping: {CASES} not found. Generate it with:\n  \
             python oracle/gen_oracle.py {MODEL} oracle/corpus_ascii.txt > {CASES}\n  \
             python oracle/gen_oracle.py {MODEL} oracle/corpus_unicode.txt >> {CASES}"
        );
        return;
    }

    let sp = SentencePieceProcessor::open(MODEL).expect("load model");
    let data = std::fs::read_to_string(CASES).expect("read cases");

    let mut checked = 0usize;
    for (lineno, line) in data.lines().enumerate() {
        let line = line.trim_end();
        if line.is_empty() {
            continue;
        }
        let (hex_text, ids_str) = line.split_once('\t').expect("malformed case line");
        let text = String::from_utf8(hex_decode(hex_text)).expect("utf8 text");
        let expected: Vec<i32> = ids_str
            .split_whitespace()
            .map(|t| t.parse().unwrap())
            .collect();

        let got = sp.encode(&text).expect("encode");
        assert_eq!(
            got,
            expected,
            "mismatch on line {} for input {:?}",
            lineno + 1,
            text
        );
        checked += 1;
    }

    assert!(checked > 0, "oracle file contained no cases");
    eprintln!("verified {checked} cases against the Python oracle");
}
